  <script src="https://unpkg.com/@babel/standalone/babel.min.js"></script>

  <script type="text/babel">
    const { useEffect, useMemo, useState } = React;

    function round3(n) {
      // Ensure numeric and stable rounding to 3 decimals.
      const x = Number.isFinite(n) ? n : 0;
      return Math.round(x * 1000) / 1000;
    }

    function countWordsDeterministic(text) {
      // Must match behavior of /\b[\w'-]+\b/g
      const m = text.match(/\b[\w'-]+\b/g);
      return m ? m.length : 0;
    }

    function countCitations(text) {
      // Bracket style citations: [1], [42]
      const m = text.match(/\[(\d+)\]/g);
      return m ? m.length : 0;
    }

    function countKeyword(text, keyword) {
      const re = new RegExp(`\\b${keyword}\\b`, 'gi');
      const m = text.match(re);
      return m ? m.length : 0;
    }

    function firstNonEmptySentence(textBlock) {
      const t = (textBlock || '').replace(/\s+/g, ' ').trim();
      if (!t) return '';
      // Simple sentence split: first chunk ending with . ! ? (or whole line if none)
      const m = t.match(/^(.+?[.!?])(\s|$)/);
      return m ? m[1].trim() : t;
    }

    function summarizeMarkdown(mdText) {
      const lines = (mdText || '').split(/\r?\n/);
      const summaries = [];
      let currentTitle = null;
      let currentBody = [];

      function flush() {
        if (currentTitle == null) return;
        const body = currentBody.join('\n');
        const summary = firstNonEmptySentence(body);
        summaries.push({ title: currentTitle, summary });
      }

      for (let i = 0; i < lines.length; i++) {
        const line = lines[i];
        const headerMatch = line.match(/^\s*#+\s*(.+?)\s*$/);
        if (headerMatch) {
          flush();
          currentTitle = headerMatch[1];
          currentBody = [];
        } else {
          // Keep all lines; summary function will find first non-empty sentence.
          if (currentTitle != null) currentBody.push(line);
        }
      }
      flush();

      // If there are no markdown headers, treat entire doc as one section.
      if (summaries.length === 0) {
        const summary = firstNonEmptySentence(mdText);
        return [{ title: 'Document', summary }];
      }

      return summaries;
    }

    function summarizeByHeadingsLoose(text) {
      // For PDFs: attempt to recover headings in a lightweight way.
      // Heuristics: lines that look like headings (ALL CAPS, or Title Case, or short lines)
      const lines = (text || '').split(/\r?\n/).map(l => l.trim());
      const isHeading = (l) => {
        if (!l) return false;
        if (l.length > 80) return false;
        // If line ends with punctuation typical of sentences, less likely heading
        if (/[.!?]$/.test(l)) return false;
        // Contains many letters; avoid pure numbers
        if (!/[A-Za-z]/.test(l)) return false;
        const alpha = (l.match(/[A-Za-z]/g) || []).length;
        if (alpha < 3) return false;
        // ALL CAPS headings
        if (l === l.toUpperCase() && /[A-Z]/.test(l)) return true;
        // Title-ish: not too many words
        const wc = (l.match(/\b[\w'-]+\b/g) || []).length;
        if (wc <= 10) return true;
        return false;
      };

      const sections = [];
      let currentTitle = null;
      let body = [];

      function flush() {
        if (currentTitle == null) return;
        const summary = firstNonEmptySentence(body.join(' '));
        sections.push({ title: currentTitle, summary });
      }

      for (let i = 0; i < lines.length; i++) {
        const l = lines[i];
        if (isHeading(l)) {
          flush();
          currentTitle = l;
          body = [];
        } else {
          if (currentTitle != null && l) body.push(l);
        }
      }
      flush();

      if (sections.length === 0) {
        return [{ title: 'Document', summary: firstNonEmptySentence(text) }];
      }
      return sections;
    }

    function decodePdfLikeText(arrayBuffer) {
      // Lightweight extraction suitable for simple text-based PDF fixtures.
      // Strategy: decode bytes as latin1 to preserve 1:1 mapping, then
      // extract strings inside parentheses that appear in text-show operators.
      // This is not a full PDF parser.
      const bytes = new Uint8Array(arrayBuffer);
      let raw = '';
      for (let i = 0; i < bytes.length; i++) raw += String.fromCharCode(bytes[i]);

      // Extract literal strings (...) while handling escaped \( \) \\ and \n\r\t
      const out = [];
      for (let i = 0; i < raw.length; i++) {
        if (raw[i] === '(') {
          let j = i + 1;
          let s = '';
          let depth = 1;
          while (j < raw.length && depth > 0) {
            const ch = raw[j];
            if (ch === '\\') {
              const next = raw[j + 1];
              if (next === 'n') { s += '\n'; j += 2; continue; }
              if (next === 'r') { s += '\r'; j += 2; continue; }
              if (next === 't') { s += '\t'; j += 2; continue; }
              if (next === '(' || next === ')' || next === '\\') { s += next; j += 2; continue; }
              // Octal escapes (e.g., \053)
              const oct = raw.slice(j + 1, j + 4);
              if (/^[0-7]{3}$/.test(oct)) {
                s += String.fromCharCode(parseInt(oct, 8));
                j += 4;
                continue;
              }
              // Fallback: keep next char
              if (typeof next === 'string') { s += next; j += 2; continue; }
            }
            if (ch === '(') { depth++; s += ch; j++; continue; }
            if (ch === ')') {
              depth--;
              if (depth === 0) { j++; break; }
              s += ch; j++; continue;
            }
            s += ch;
            j++;
          }
          // Heuristic: keep only reasonably texty strings
          const cleaned = s.replace(/\u0000/g, '').trim();
          if (cleaned && /[A-Za-z0-9]/.test(cleaned)) out.push(cleaned);
          i = j - 1;
        }
      }

      // Join with newlines; also normalize multiple spaces.
      const joined = out.join('\n').replace(/\r\n/g, '\n');
      return joined;
    }

    function analyzeText(text, fileType) {
      const totalWords = countWordsDeterministic(text);
      const citations = countCitations(text);
      const quantumCount = countKeyword(text, 'quantum');
      const entanglementCount = countKeyword(text, 'entanglement');

      const keywordDensity = {
        quantum: {
          count: quantumCount,
          density: round3(totalWords ? (quantumCount / totalWords) : 0)
        },
        entanglement: {
          count: entanglementCount,
          density: round3(totalWords ? (entanglementCount / totalWords) : 0)
        }
      };

      const sectionSummaries = (fileType === 'markdown')
        ? summarizeMarkdown(text)
        : summarizeByHeadingsLoose(text);

      return {
        fileType,
        citations,
        totalWords,
        keywordDensity,
        sectionSummaries
      };
    }

    function App() {
      const empty = useMemo(() => ({
        fileType: null,
        citations: 0,
        totalWords: 0,
        keywordDensity: {
          quantum: { count: 0, density: 0 },
          entanglement: { count: 0, density: 0 }
        },
        sectionSummaries: []
      }), []);

      const [status, setStatus] = useState('No file loaded.');
      const [analysis, setAnalysis] = useState(empty);

      async function handleFile(file) {
        if (!file) return;
        const name = file.name || '';
        const ext = name.toLowerCase().split('.').pop();

        try {
          setStatus(`Loading: ${name}`);

          if (ext === 'md' || ext === 'markdown') {
            const text = await file.text();
            const next = analyzeText(text, 'markdown');
            setAnalysis(next);
            setStatus(`Loaded ${name} (${next.totalWords} words)`);
            return;
          }

          if (ext === 'pdf') {
            const buf = await file.arrayBuffer();
            const text = decodePdfLikeText(buf);
            const next = analyzeText(text, 'pdf');
            setAnalysis(next);
            setStatus(`Loaded ${name} (${next.totalWords} words)`);
            return;
          }

          setStatus('Unsupported file type. Please upload .md, .markdown, or .pdf');
        } catch (e) {
          console.error(e);
          setStatus('Error reading file.');
        }
      }

      return (
        <div>
          <h1>Journal Analyzer</h1>

          <div className="card">
            <label htmlFor="file">Upload Journal File</label>
            <div className="muted">Accepted: .md, .markdown, .pdf</div>
            <input
              id="file"
              type="file"
              accept=".md,.markdown,.pdf,application/pdf,text/markdown"
              onChange={(e) => handleFile(e.target.files && e.target.files[0])}
            />
          </div>

          <div className="status" aria-live="polite">{status}</div>

          <div className="row">
            <div className="card">
              <h2>Citation Frequency</h2>
              <div><strong>Total citations:</strong> {analysis.citations}</div>
            </div>

            <div className="card">
              <h2>Keyword Density</h2>
              <div><strong>Total words:</strong> {analysis.totalWords}</div>
              <div style={{ marginTop: 8 }}>
                <div><strong>quantum</strong>: {analysis.keywordDensity.quantum.count} (density: {analysis.keywordDensity.quantum.density})</div>
                <div><strong>entanglement</strong>: {analysis.keywordDensity.entanglement.count} (density: {analysis.keywordDensity.entanglement.density})</div>
              </div>
            </div>

            <div className="card sections">
              <h2>Section Summaries</h2>
              {analysis.sectionSummaries.length === 0 ? (
                <div className="muted">No sections detected yet.</div>
              ) : (
                <ul>
                  {analysis.sectionSummaries.map((s, idx) => (
                    <li key={idx}>
                      <strong>{s.title}</strong>
                      <div className="muted">{s.summary || '(No summary found)'}</div>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          </div>

          <h2 style={{ marginTop: 18 }}>Analysis JSON</h2>
          <pre id="analysis-output">{JSON.stringify(analysis, null, 2)}</pre>
        </div>
      );
    }

    ReactDOM.createRoot(document.getElementById('root')).render(<App />);
  </script>
</body>
</html>
